type ToolCall = { name: string; arguments: Record<string, unknown> };

export function parseToolCall(raw: string): ToolCall {
  const parsed = JSON.parse(raw) as Partial<ToolCall>;
  if (typeof parsed.name !== "string" || parsed.name.length === 0) {
    throw new Error("tool call missing name");
  }
  return { name: parsed.name, arguments: parsed.arguments ?? {} };
}
```
Unknown fields are dropped rather than guessed; a missing name is an error.
